#include <stdio.h>
#include <string.h>
#include <time.h>
#include <stdbool.h>

bool contains_subsequence(const char *arr, const char *seq) {
    int seq_len = strlen(seq);

    if (seq_len == 0) {
        return true;
    }

    int i = 0;
    for (int j = 0; arr[j] != '\0'; j++) {
        if (arr[j] == seq[i]) {
            i++;
            if (i == seq_len) {
                break;
            }
        }
    }

    return i == seq_len;
}

int main() {
    char line[1000];
    fgets(line, sizeof(line), stdin);
    line[strcspn(line, "\n")] = '\0';

    if (contains_subsequence(line, "hello")) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

    return 0;
}
